<?php
declare(strict_types=1);
require_once __DIR__.'/../services/AdministracaoService.php';require_once __DIR__.'/../repositories/AuditoriaConsultaRepository.php';
final class AdministracaoApiController
{
 private $service,$query;public function __construct(){$db=Database::getConnection();$this->service=new AdministracaoService($db);$this->query=new AuditoriaConsultaRepository($db);}
 public function handle($resource='usuarios',$id=null){$actor=Auth::requirePermission($resource==='auditoria'?'auditoria':'administracao',$resource==='auditoria'?'visualizar':'gerenciar',true);try{if(Request::method()==='GET'){if($resource==='usuarios')return Response::success($this->service->users($_GET,isset($_GET['page'])?$_GET['page']:1,isset($_GET['perPage'])?$_GET['perPage']:25));if($resource==='validacao')return Response::success($this->service->validationUsers());if($resource==='configuracoes')return Response::success($this->service->configurations());if($resource==='auditoria')return Response::success($this->query->audit($_GET,isset($_GET['page'])?$_GET['page']:1,isset($_GET['perPage'])?$_GET['perPage']:25));if($resource==='acessos')return Response::success($this->query->accesses($_GET,isset($_GET['page'])?$_GET['page']:1,isset($_GET['perPage'])?$_GET['perPage']:25));}Auth::requireCsrf();$p=Request::json();if($resource==='usuarios'&&in_array(Request::method(),array('POST','PUT','PATCH'),true))return Response::success($this->service->saveUser($id,$p,$actor,!empty($p['confirmarProprioAcesso'])),$id?'Usuario atualizado.':'Usuario criado.',$id?200:201);if($resource==='configuracoes'&&in_array(Request::method(),array('PUT','PATCH'),true)){$this->service->saveConfiguration((string)$id,isset($p['valor'])?$p['valor']:null,$actor);return Response::success(array(),'Configuracao atualizada.');}Response::error('Metodo ou recurso nao permitido.',405);}catch(DomainException$e){Response::error($e->getMessage(),422);}catch(LogicException$e){Response::error($e->getMessage(),409);}catch(OutOfBoundsException$e){Response::error($e->getMessage(),404);}}
}
